<div class="container-fluid mt-3">
    <div class="d-flex justify-content-between align-items-center mb-3">
        <h2>📋 Shipment Dashboard</h2>
        <button class="btn btn-success" @onclick="ShowCreateForm">
            ➕ New Shipment
        </button>
    </div>

    @if (showCreateForm)
    {
        <div class="card mb-4 border-success">
            <div class="card-header bg-success text-white d-flex justify-content-between align-items-center">
                <strong>Create New Shipment</strong>
                <button class="btn btn-sm btn-outline-light" @onclick="CancelCreate">✕</button>
            </div>
            <div class="card-body">
                <div class="row g-3">
                    <div class="col-md-4">
                        <label class="form-label">Origin</label>
                        <input class="form-control" @bind="newShipment.Origin" placeholder="City, State" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Destination</label>
                        <input class="form-control" @bind="newShipment.Destination" placeholder="City, State" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Customer Email</label>
                        <input class="form-control" type="email" @bind="newShipment.CustomerEmail" placeholder="customer@example.com" />
                    </div>
                    <div class="col-md-6">
                        <label class="form-label">Description</label>
                        <input class="form-control" @bind="newShipment.Description" placeholder="Package description" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Estimated Delivery</label>
                        <input class="form-control" type="date" @bind="newShipment.EstimatedDelivery" />
                    </div>
                    <div class="col-md-3 d-flex align-items-end">
                        <button class="btn btn-success w-100" @onclick="CreateShipment" disabled="@isSaving">
                            @if (isSaving)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Create Shipment
                        </button>
                    </div>
                </div>
            </div>
        </div>
    }

    <div class="row mb-3">
        <div class="col-md-4">
            <input class="form-control" placeholder="🔍 Filter by tracking #, origin, or destination..."
                   @bind="filterText" @bind:event="oninput" />
        </div>
        <div class="col-md-3">
            <select class="form-select" @bind="statusFilter">
                <option value="">All Statuses</option>
                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                {
                    <option value="@status">@status</option>
                }
            </select>
        </div>
        <div class="col-md-2">
            <button class="btn btn-outline-secondary w-100" @onclick="RefreshShipments">
                🔄 Refresh
            </button>
        </div>
    </div>

    @if (isLoading)
    {
        <div class="text-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
            <p class="mt-2 text-muted">Loading shipments...</p>
        </div>
    }
    else if (errorMessage is not null)
    {
        <div class="alert alert-danger">@errorMessage</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th role="button" @onclick='() => SortBy("TrackingNumber")'>
                            Tracking # @SortIndicator("TrackingNumber")
                        </th>
                        <th role="button" @onclick='() => SortBy("Origin")'>
                            Origin @SortIndicator("Origin")
                        </th>
                        <th role="button" @onclick='() => SortBy("Destination")'>
                            Destination @SortIndicator("Destination")
                        </th>
                        <th role="button" @onclick='() => SortBy("Status")'>
                            Status @SortIndicator("Status")
                        </th>
                        <th role="button" @onclick='() => SortBy("EstimatedDelivery")'>
                            Est. Delivery @SortIndicator("EstimatedDelivery")
                        </th>
                        <th>Customer</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var shipment in FilteredShipments)
                    {
                        <tr>
                            <td><code>@shipment.TrackingNumber</code></td>
                            <td>@shipment.Origin</td>
                            <td>@shipment.Destination</td>
                            <td>
                                @if (editingShipmentId == shipment.Id)
                                {
                                    <select class="form-select form-select-sm" @bind="editStatus">
                                        @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                        {
                                            <option value="@status">@status</option>
                                        }
                                    </select>
                                }
                                else
                                {
                                    <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
                                }
                            </td>
                            <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")</td>
                            <td>@shipment.CustomerEmail</td>
                            <td>
                                @if (editingShipmentId == shipment.Id)
                                {
                                    <button class="btn btn-sm btn-success me-1" @onclick="() => SaveStatusUpdate(shipment)">Save</button>
                                    <button class="btn btn-sm btn-secondary" @onclick="CancelEdit">Cancel</button>
                                }
                                else
                                {
                                    <button class="btn btn-sm btn-outline-primary" @onclick="() => StartEdit(shipment)">
                                        ✏️ Update Status
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
    }
</div>

@code {
    private List<Shipment> shipments = [];
    private bool isLoading = true;
    private bool isSaving;
    private string? errorMessage;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;
    private string sortColumn = "LastUpdated";
    private bool sortAscending;

    private bool showCreateForm;
    private Shipment newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };

    private int? editingShipmentId;
    private ShipmentStatus editStatus;

    protected override async Task OnInitializedAsync()
    {
        await RefreshShipments();
    }

    private async Task RefreshShipments()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private IEnumerable<Shipment> FilteredShipments
    {
        get
        {
            var filtered = shipments.AsEnumerable();

            if (!string.IsNullOrWhiteSpace(filterText))
            {
                var term = filterText.Trim();
                filtered = filtered.Where(s =>
                    s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                    s.Origin.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                    s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase));
            }

            if (!string.IsNullOrWhiteSpace(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var status))
            {
                filtered = filtered.Where(s => s.Status == status);
            }

            filtered = sortColumn switch
            {
                "TrackingNumber" => sortAscending ? filtered.OrderBy(s => s.TrackingNumber) : filtered.OrderByDescending(s => s.TrackingNumber),
                "Origin" => sortAscending ? filtered.OrderBy(s => s.Origin) : filtered.OrderByDescending(s => s.Origin),
                "Destination" => sortAscending ? filtered.OrderBy(s => s.Destination) : filtered.OrderByDescending(s => s.Destination),
                "Status" => sortAscending ? filtered.OrderBy(s => s.Status) : filtered.OrderByDescending(s => s.Status),
                "EstimatedDelivery" => sortAscending ? filtered.OrderBy(s => s.EstimatedDelivery) : filtered.OrderByDescending(s => s.EstimatedDelivery),
                _ => sortAscending ? filtered.OrderBy(s => s.LastUpdated) : filtered.OrderByDescending(s => s.LastUpdated)
            };

            return filtered;
        }
    }

    private void SortBy(string column)
    {
        if (sortColumn == column)
            sortAscending = !sortAscending;
        else
        {
            sortColumn = column;
            sortAscending = true;
        }
    }

    private string SortIndicator(string column)
    {
        if (sortColumn != column) return "";
        return sortAscending ? "▲" : "▼";
    }

    private void ShowCreateForm() => showCreateForm = true;
    private void CancelCreate()
    {
        showCreateForm = false;
        newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };
    }

    private async Task CreateShipment()
    {
        isSaving = true;
        try
        {
            await ShipmentService.CreateShipmentAsync(newShipment);
            CancelCreate();
            await RefreshShipments();
        }
        finally
        {
            isSaving = false;
        }
    }

    private void StartEdit(Shipment shipment)
    {
        editingShipmentId = shipment.Id;
        editStatus = shipment.Status;
    }

    private void CancelEdit() => editingShipmentId = null;

    private async Task SaveStatusUpdate(Shipment shipment)
    {
        shipment.Status = editStatus;
        await ShipmentService.UpdateShipmentAsync(shipment);
        editingShipmentId = null;
        await RefreshShipments();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };
}

