@page "/"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@inject NavigationManager Navigation

<PageTitle>ShipmentTracker - Track Your Shipment</PageTitle>

<div class="container mt-4">
    <div class="text-center mb-5">
        <h1>📦 ShipmentTracker</h1>
        <p class="lead">Track your shipments in real time</p>
    </div>

    <div class="row justify-content-center">
        <div class="col-md-8">
            <div class="card shadow">
                <div class="card-body p-4">
                    <h4 class="card-title mb-3">Track a Shipment</h4>
                    <div class="input-group input-group-lg">
                        <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-20260101-10001)"
                               @bind="trackingNumber" @bind:event="oninput"
                               @onkeydown="HandleKeyDown" />
                        <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                            @if (isLoading)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Track
                        </button>
                    </div>

                    @if (notFound)
                    {
                        <div class="alert alert-warning mt-3">
                            <strong>Not found.</strong> No shipment matches tracking number "@searchedNumber".
                        </div>
                    }

                    @if (trackedShipment is not null)
                    {
                        <div class="card mt-4">
                            <div class="card-header d-flex justify-content-between align-items-center">
                                <strong>@trackedShipment.TrackingNumber</strong>
                                <span class="badge @GetStatusBadgeClass(trackedShipment.Status)">@trackedShipment.Status</span>
                            </div>
                            <div class="card-body">
                                <div class="row">
                                    <div class="col-md-6">
                                        <p><strong>Origin:</strong> @trackedShipment.Origin</p>
                                        <p><strong>Destination:</strong> @trackedShipment.Destination</p>
                                        <p><strong>Description:</strong> @trackedShipment.Description</p>
                                    </div>
                                    <div class="col-md-6">
                                        <p><strong>Estimated Delivery:</strong>
                                            @(trackedShipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")</p>
                                        <p><strong>Last Updated:</strong> @trackedShipment.LastUpdated.ToString("MMM dd, yyyy HH:mm UTC")</p>
                                    </div>
                                </div>
                            </div>
                        </div>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="text-center mt-4">
        <AuthorizeView>
            <Authorized>
                <a href="shipments" class="btn btn-outline-primary">View All Shipments</a>
            </Authorized>
            <NotAuthorized>
                <p class="text-muted">
                    <a href="Account/Login">Log in</a> to manage shipments.
                </p>
            </NotAuthorized>
        </AuthorizeView>
    </div>
</div>

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private Shipment? trackedShipment;
    private bool notFound;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            await TrackShipment();
        }
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        notFound = false;
        trackedShipment = null;
        searchedNumber = trackingNumber.Trim();

        try
        {
            trackedShipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchedNumber);
            notFound = trackedShipment is null;
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.Cancelled => "bg-dark",
        _ => "bg-secondary"
    };
}

