167. @code {
168.     private List<Shipment> shipments = [];
169.     private bool isLoading = true;
170.     private bool isSaving;
171.     private string? errorMessage;
172.     private string filterText = string.Empty;
173.     private string statusFilter = string.Empty;
174.     private string sortColumn = "LastUpdated";
175.     private bool sortAscending;
176. 
177.     private bool showCreateForm;
178.     private Shipment newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };
179. 
180.     private int? editingShipmentId;
181.     private ShipmentStatus editStatus;
182. 
183.     protected override async Task OnInitializedAsync()
184.     {
185.         await RefreshShipments();
186.     }
187. 
188.     private async Task RefreshShipments()
189.     {
190.         isLoading = true;
191.         errorMessage = null;
192.         try
193.         {
194.             shipments = await ShipmentService.GetAllShipmentsAsync();
195.         }
196.         catch (Exception ex)
197.         {
198.             errorMessage = $"Failed to load shipments: {ex.Message}";
199.         }
200.         finally
201.         {
202.             isLoading = false;
203.         }
204.     }
205. 
206.     private IEnumerable<Shipment> FilteredShipments
207.     {
208.         get
209.         {
210.             var filtered = shipments.AsEnumerable();
211. 
212.             if (!string.IsNullOrWhiteSpace(filterText))
213.             {
214.                 var term = filterText.Trim();
215.                 filtered = filtered.Where(s =>
216.                     s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase) ||
217.                     s.Origin.Contains(term, StringComparison.OrdinalIgnoreCase) ||
218.                     s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase));
219.             }
220. 
221.             if (!string.IsNullOrWhiteSpace(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var status))
222.             {
223.                 filtered = filtered.Where(s => s.Status == status);
224.             }
225. 
226.             filtered = sortColumn switch
227.             {
228.                 "TrackingNumber" => sortAscending ? filtered.OrderBy(s => s.TrackingNumber) : filtered.OrderByDescending(s => s.TrackingNumber),
229.                 "Origin" => sortAscending ? filtered.OrderBy(s => s.Origin) : filtered.OrderByDescending(s => s.Origin),
230.                 "Destination" => sortAscending ? filtered.OrderBy(s => s.Destination) : filtered.OrderByDescending(s => s.Destination),
231.                 "Status" => sortAscending ? filtered.OrderBy(s => s.Status) : filtered.OrderByDescending(s => s.Status),
232.                 "EstimatedDelivery" => sortAscending ? filtered.OrderBy(s => s.EstimatedDelivery) : filtered.OrderByDescending(s => s.EstimatedDelivery),
233.                 _ => sortAscending ? filtered.OrderBy(s => s.LastUpdated) : filtered.OrderByDescending(s => s.LastUpdated)
234.             };
235. 
236.             return filtered;
237.         }
238.     }
239. 
240.     private void SortBy(string column)
241.     {
242.         if (sortColumn == column)
243.             sortAscending = !sortAscending;
244.         else
245.         {
246.             sortColumn = column;
247.             sortAscending = true;
248.         }
249.     }
250. 
251.     private string SortIndicator(string column)
252.     {
253.         if (sortColumn != column) return "";
254.         return sortAscending ? "▲" : "▼";
255.     }
256. 
257.     private void ShowCreateForm() => showCreateForm = true;
258.     private void CancelCreate()
259.     {
260.         showCreateForm = false;
261.         newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };
262.     }
263. 
264.     private async Task CreateShipment()
265.     {
266.         isSaving = true;
267.         try
268.         {
269.             await ShipmentService.CreateShipmentAsync(newShipment);
270.             CancelCreate();
271.             await RefreshShipments();
272.         }
273.         finally
274.         {
275.             isSaving = false;
276.         }
277.     }
278. 
279.     private void StartEdit(Shipment shipment)
280.     {
281.         editingShipmentId = shipment.Id;
282.         editStatus = shipment.Status;
283.     }
284. 
285.     private void CancelEdit() => editingShipmentId = null;
286. 
287.     private async Task SaveStatusUpdate(Shipment shipment)
288.     {
289.         shipment.Status = editStatus;
290.         await ShipmentService.UpdateShipmentAsync(shipment);
291.         editingShipmentId = null;
292.         await RefreshShipments();
293.     }
294. 
295.     private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
296.     {
297.         ShipmentStatus.Pending => "bg-secondary",
298.         ShipmentStatus.PickedUp => "bg-info",
299.         ShipmentStatus.InTransit => "bg-primary",
300.         ShipmentStatus.OutForDelivery => "bg-warning text-dark",
301.         ShipmentStatus.Delivered => "bg-success",
302.         ShipmentStatus.Delayed => "bg-danger",
303.         ShipmentStatus.Cancelled => "bg-dark",
304.         _ => "bg-secondary"
305.     };
306. }
307.

