                             <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "TBD")</td>
                             <td>@shipment.CustomerEmail</td>
                             <td>
                                 @if (editingShipmentId == shipment.Id)
                                 {
                                     <button class="btn btn-sm btn-success me-1" @onclick="() => SaveStatusUpdate(shipment)">Save</button>
                                     <button class="btn btn-sm btn-secondary" @onclick="CancelEdit">Cancel</button>
                                 }
                                 else
                                 {
                                     <button class="btn btn-sm btn-outline-primary" @onclick="() => StartEdit(shipment)">
                                         ✏️ Update Status
                                     </button>
                                 }
                             </td>
                         </tr>
                     }
                 </tbody>
             </table>
         </div>

         <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
     }
 </div>

 @code {
     private List<Shipment> shipments = [];
     private bool isLoading = true;
     private bool isSaving;
     private string? errorMessage;
     private string filterText = string.Empty;
     private string statusFilter = string.Empty;
     private string sortColumn = "LastUpdated";
     private bool sortAscending;

     private bool showCreateForm;
     private Shipment newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };

     private int? editingShipmentId;
     private ShipmentStatus editStatus;

     protected override async Task OnInitializedAsync()
     {
         await RefreshShipments();
     }

     private async Task RefreshShipments()
     {
         isLoading = true;
         errorMessage = null;
         try
         {
             shipments = await ShipmentService.GetAllShipmentsAsync();
         }
         catch (Exception ex)
         {
             errorMessage = $"Failed to load shipments: {ex.Message}";
         }
         finally
         {
             isLoading = false;
         }
     }

     private IEnumerable<Shipment> FilteredShipments
     {
         get
         {
             var filtered = shipments.AsEnumerable();

             if (!string.IsNullOrWhiteSpace(filterText))
             {
                 var term = filterText.Trim();
                 filtered = filtered.Where(s =>
                     s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                     s.Origin.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                     s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase));
             }

             if (!string.IsNullOrWhiteSpace(statusFilter) && Enum.TryParse<ShipmentStatus>(statusFilter, out var status))
             {
                 filtered = filtered.Where(s => s.Status == status);
             }

             filtered = sortColumn switch
             {
                 "TrackingNumber" => sortAscending ? filtered.OrderBy(s => s.TrackingNumber) : filtered.OrderByDescending(s => s.TrackingNumber),
                 "Origin" => sortAscending ? filtered.OrderBy(s => s.Origin) : filtered.OrderByDescending(s => s.Origin),
                 "Destination" => sortAscending ? filtered.OrderBy(s => s.Destination) : filtered.OrderByDescending(s => s.Destination),
                 "Status" => sortAscending ? filtered.OrderBy(s => s.Status) : filtered.OrderByDescending(s => s.Status),
                 "EstimatedDelivery" => sortAscending ? filtered.OrderBy(s => s.EstimatedDelivery) : filtered.OrderByDescending(s => s.EstimatedDelivery),
                 _ => sortAscending ? filtered.OrderBy(s => s.LastUpdated) : filtered.OrderByDescending(s => s.LastUpdated)
             };

             return filtered;
         }
     }

     private void SortBy(string column)
     {
         if (sortColumn == column)
             sortAscending = !sortAscending;
         else
         {
             sortColumn = column;
             sortAscending = true;
         }
     }

     private string SortIndicator(string column)
     {
         if (sortColumn != column) return "";
         return sortAscending ? "▲" : "▼";
     }

     private void ShowCreateForm() => showCreateForm = true;
     private void CancelCreate()
     {
         showCreateForm = false;
         newShipment = new() { EstimatedDelivery = DateTime.UtcNow.AddDays(7) };
     }

     private async Task CreateShipment()
     {
         isSaving = true;
         try
         {
             await ShipmentService.CreateShipmentAsync(newShipment);
             CancelCreate();
             await RefreshShipments();
         }
         finally
         {
             isSaving = false;
         }
     }

     private void StartEdit(Shipment shipment)
     {
         editingShipmentId = shipment.Id;
         editStatus = shipment.Status;
     }

     private void CancelEdit() => editingShipmentId = null;

     private async Task SaveStatusUpdate(Shipment shipment)
     {
         shipment.Status = editStatus;
         await ShipmentService.UpdateShipmentAsync(shipment);
         editingShipmentId = null;
         await RefreshShipments();
     }

     private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
     {
         ShipmentStatus.Pending => "bg-secondary",
         ShipmentStatus.PickedUp => "bg-info",
         ShipmentStatus.InTransit => "bg-primary",
         ShipmentStatus.OutForDelivery => "bg-warning text-dark",
         ShipmentStatus.Delivered => "bg-success",
         ShipmentStatus.Delayed => "bg-danger",
         ShipmentStatus.Cancelled => "bg-dark",
         _ => "bg-secondary"
     };
 }

